// src/Login.js
import React, { useState } from "react";

function Login({ onLoginSuccess }) {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  // use your live render URL
  const apiBase = "https://prasa-backend-1.onrender.com";

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!empld || !password) {
      setError("Please enter empld and password.");
      return;
    }

    try {
      const res = await fetch(`${apiBase}/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ empld, password }),
      });

      if (!res.ok) {
        const errBody = await res.json().catch(() => ({}));
        setError(errBody.message || "Login failed");
        return;
      }

      const body = await res.json();

      if (body.success) {
        // send employee object to parent
        onLoginSuccess(body.employee);
      } else {
        setError(body.message || "Invalid credentials");
      }
    } catch (err) {
      console.error("Login error:", err);
      setError("Server error. Please try again.");
    }
  };

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        height: "100vh",
        backgroundColor: "#f5f5f5",
      }}
    >
      <img
        src="/logo.png"
        alt="PRASA Logo"
        style={{
          width: "140px",
          height: "140px",
          objectFit: "contain",
          background: "white",
          borderRadius: 20,
          padding: 18,
          boxShadow: "0 4px 20px rgba(0,0,0,0.12)",
          marginBottom: 20,
        }}
      />

      <h2>PRASA Employee Login</h2>

      <form
        onSubmit={handleLogin}
        style={{ display: "flex", flexDirection: "column", width: 320 }}
      >
        <input
          type="text"
          placeholder="Employee ID (empld)"
          value={empld}
          onChange={(e) => setEmpld(e.target.value)}
          style={{ marginBottom: 10, padding: 10 }}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          style={{ marginBottom: 10, padding: 10 }}
        />

        <button
          type="submit"
          style={{
            backgroundColor: "#0078d4",
            color: "white",
            border: "none",
            padding: 12,
            cursor: "pointer",
            borderRadius: 4,
          }}
        >
          Login
        </button>
      </form>

      {error && <p style={{ color: "red", marginTop: 12 }}>{error}</p>}
    </div>
  );
}

export default Login;
